export function thumb(url) {
    if (!url) return url;
    const entry = THUMBS[url];
    return (entry && entry.path) || url;
}

export function thumbDims(url) {
    const entry = url && THUMBS[url];
    return entry ? { w: entry.w, h: entry.h } : null;
}
